// Package grpc contains the inbound ConnectRPC adapter for the sensor-service.
// NOTE: proto types are generated by buf generate.
package grpc

import (
	"context"

	"p9e.in/samavaya/packages/errors"
	"p9e.in/samavaya/packages/p9context"
	"p9e.in/samavaya/packages/p9log"

	// Generated by buf generate
	pb "p9e.in/samavaya/agriculture/sensor-service/api/v1"
	"p9e.in/samavaya/agriculture/sensor-service/internal/domain"
	"p9e.in/samavaya/agriculture/sensor-service/internal/ports/inbound"
)

// SensorHandler is the ConnectRPC inbound adapter.
type SensorHandler struct {
	svc inbound.SensorService
	log *p9log.Helper
}

// NewSensorHandler creates a new ConnectRPC sensor handler.
func NewSensorHandler(svc inbound.SensorService, log p9log.Logger) *SensorHandler {
	return &SensorHandler{
		svc: svc,
		log: p9log.NewHelper(p9log.With(log, "component", "SensorHandler")),
	}
}

// CreateSensor handles creation requests.
func (h *SensorHandler) CreateSensor(ctx context.Context, req *pb.CreateSensorRequest) (*pb.CreateSensorResponse, error) {
	h.log.Infow("msg", "CreateSensor request", "tenant_id", p9context.TenantID(ctx))
	if req.GetName() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "name is required")
	}
	entity := &domain.Sensor{Name: req.GetName()}
	created, err := h.svc.CreateSensor(ctx, entity)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.CreateSensorResponse{Sensor: sensorToProto(created)}, nil
}

// GetSensor handles get requests.
func (h *SensorHandler) GetSensor(ctx context.Context, req *pb.GetSensorRequest) (*pb.GetSensorResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	entity, err := h.svc.GetSensor(ctx, req.GetId())
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.GetSensorResponse{Sensor: sensorToProto(entity)}, nil
}

// ListSensors handles list requests.
func (h *SensorHandler) ListSensors(ctx context.Context, req *pb.ListSensorsRequest) (*pb.ListSensorsResponse, error) {
	params := domain.ListSensorParams{PageSize: req.GetPageSize()}
	entities, total, err := h.svc.ListSensors(ctx, params)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	protos := make([]*pb.Sensor, 0, len(entities))
	for i := range entities {
		protos = append(protos, sensorToProto(&entities[i]))
	}
	return &pb.ListSensorsResponse{Sensors: protos, TotalCount: total}, nil
}

// UpdateSensor handles update requests.
func (h *SensorHandler) UpdateSensor(ctx context.Context, req *pb.UpdateSensorRequest) (*pb.UpdateSensorResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	entity := &domain.Sensor{}
	entity.UUID = req.GetId()
	updated, err := h.svc.UpdateSensor(ctx, entity)
	if err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.UpdateSensorResponse{Sensor: sensorToProto(updated)}, nil
}

// DeleteSensor handles delete requests.
func (h *SensorHandler) DeleteSensor(ctx context.Context, req *pb.DeleteSensorRequest) (*pb.DeleteSensorResponse, error) {
	if req.GetId() == "" {
		return nil, errors.BadRequest("INVALID_ARGUMENT", "id is required")
	}
	if err := h.svc.DeleteSensor(ctx, req.GetId()); err != nil {
		return nil, errors.ToConnectError(err)
	}
	return &pb.DeleteSensorResponse{Success: true}, nil
}

func sensorToProto(e *domain.Sensor) *pb.Sensor {
	return &pb.Sensor{
		Id:       e.UUID,
		TenantId: e.TenantID,
		Name:     e.Name,
		Status:   string(e.Status),
	}
}
